const staticData = $getWorkflowStaticData('global');
const message = $json.message || {};
const groupId = message.media_group_id ? String(message.media_group_id) : ('single_' + message.message_id);
const key = 'album_' + groupId;
const buffer = staticData[key] || { file_ids: [], description: '', chat_id: null };
if (Array.isArray(message.photo) && message.photo.length > 0) {
  const largest = message.photo[message.photo.length - 1];
  if (largest && largest.file_id && !buffer.file_ids.includes(largest.file_id)) buffer.file_ids.push(largest.file_id);
}
if (message.caption) buffer.description = message.caption;
if (message.chat && message.chat.id) buffer.chat_id = message.chat.id;
staticData[key] = buffer;
if (buffer.file_ids.length >= 2) {
  delete staticData[key];
  return [{ json: { chat_id: buffer.chat_id, description: buffer.description, file_id_1: buffer.file_ids[0], file_id_2: buffer.file_ids[1] } }];
}
return [];
